it("Blinker oscillator: vertical [(0,0), (0,1), (0,2)] becomes horizontal [(-1,1), (0,1), (1,1)]", () => {
  const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
  expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
  expect(result).toHaveLength(3);
});
